code = """import json
import re

businesses = locals()['var_function-call-12386215528452714107']
if isinstance(businesses, str):
    with open(businesses, 'r') as f:
        businesses = json.load(f)

# Function to check if WiFi is offered
def has_wifi(attrs):
    if not attrs or attrs == 'None':
        return False
    if isinstance(attrs, dict):
        wifi = attrs.get('WiFi')
        if wifi:
            # Normalize string
            wifi_str = str(wifi).lower()
            if 'free' in wifi_str or 'paid' in wifi_str:
                return True
    return False

# Function to extract state
def extract_state(desc):
    # Pattern: " in {City}, {State}," or " in {City}, {State} "
    # Examples: 
    # "... in Goleta, CA, this ..." -> CA
    # "... in St. Louis, MO, this ..." -> MO
    # It seems to be always "Located at ... in ..., {ST}, ..."
    # Let's try to find the two-letter code after the last comma before " this" or end of string?
    # Or rely on the " in " structure.
    
    match = re.search(r" in [^,]+, ([A-Z]{2})", desc)
    if match:
        return match.group(1)
    return None

state_counts = {}
target_businesses = [] # List of tuples (state, business_id)

for b in businesses:
    if has_wifi(b.get('attributes')):
        state = extract_state(b.get('description', ''))
        if state:
            state_counts[state] = state_counts.get(state, 0) + 1
            target_businesses.append({'state': state, 'business_id': b['business_id']})

# Find max state
if not state_counts:
    print("No businesses with WiFi found.")
    max_state = None
    max_state_businesses = []
else:
    max_state = max(state_counts, key=state_counts.get)
    max_state_businesses = [b['business_id'] for b in target_businesses if b['state'] == max_state]

print("__RESULT__:")
print(json.dumps({"state_counts": state_counts, "max_state": max_state, "business_ids": max_state_businesses}))"""

